<template>
  <view class="page-container">
    <!-- 顶部标题栏 -->
    <view class="header">
      <u-icon name="arrow-left" size="24" @click="goBack"></u-icon>
      <text class="title">机构详情</text>
      <view class="placeholder"></view>
    </view>

    <!-- 加载状态 -->
    <view v-if="loading" class="loading-state">
      <u-loading-icon mode="circle"></u-loading-icon>
    </view>

    <!-- 内容区域 -->
    <scroll-view v-else-if="detail" scroll-y class="content-scroll">
      <!-- 基本信息 -->
      <view class="card">
        <text class="inst-name">{{ detail.name }}</text>
        <view class="tags-box">
          <u-tag :text="detail.typeName" type="primary" size="mini"></u-tag>
          <u-tag :text="detail.region" plain size="mini" class="ml-2"></u-tag>
        </view>
        <text class="address-text">{{ detail.address }}</text>
      </view>

      <!-- 医生团队 -->
      <view v-if="detail.doctors && detail.doctors.length > 0" class="card mt-3">
        <text class="section-title">医生团队</text>
        <u-cell-group>
          <u-cell
            v-for="(doctor, index) in detail.doctors"
            :key="index"
            :title="doctor.name"
            :label="`${doctor.title} · ${doctor.specialty}`"
          />
        </u-cell-group>
      </view>

      <!-- 联系方式 -->
      <view class="card mt-3">
        <text class="section-title">联系方式</text>
        <view class="btn-group">
          <u-button 
            size="small" 
            type="primary" 
            customStyle="width: 100%; margin-bottom: 8px;"
            @click="makeCall"
          >
            拨打电话
          </u-button>
          <u-button 
            v-if="detail.website"
            size="small" 
            plain 
            customStyle="width: 100%; margin-bottom: 8px;"
            @click="openWebsite"
          >
            复制官网链接
          </u-button>
          <u-button 
            v-if="detail.address"
            size="small" 
            plain 
            customStyle="width: 100%;"
            @click="openNavigation"
          >
            导航前往
          </u-button>
        </view>
      </view>

      <!-- 操作按钮 -->
      <view class="card mt-3">
        <u-button 
          plain 
          customStyle="width: 100%;"
          @click="goBack"
        >
          返回列表
        </u-button>
      </view>
      
      <view class="bottom-spacer"></view>
    </scroll-view>

    <!-- 空状态 -->
    <view v-else class="empty-state">
      <u-empty mode="page" text="机构不存在或已停业"></u-empty>
    </view>
  </view>
</template>

<script setup lang="ts">
import { ref } from 'vue'
import { onLoad } from '@dcloudio/uni-app'
import request from '@/utils/request'

// 类型定义
interface Doctor {
  name: string
  title: string
  specialty: string
}

interface InstitutionDetail {
  id: number
  name: string
  type: string
  typeName: string
  region: string
  regionCode: string
  address: string
  contact: string
  phone: string
  email: string
  website: string
  services: string[]
  rating: number
  isInsurance: boolean
  description: string
  coverUrl: string
  images: string[]
  businessHours: string
  facilities: string[]
  doctors: Doctor[]
  status: string
  latitude?: number
  longitude?: number
}

// 响应式数据
const detail = ref<InstitutionDetail | null>(null)
const loading = ref<boolean>(false)
const institutionId = ref<number | null>(null)

// 加载详情
const loadDetail = async (id: number) => {
  loading.value = true
  try {
    const res = await request.get(`/api/resource/rehab/institutions/${id}`)
    detail.value = res.data || res.data
  } catch (error) {
    uni.__f__('error','at pages/resource/rehab/InstitutionDetail.vue:144','加载机构详情失败:', error)
    detail.value = null
    uni.showToast({ title: '加载失败，请重试', icon: 'none' })
  } finally {
    loading.value = false
  }
}

// 拨打电话
const makeCall = () => {
  if (detail.value?.phone) {
    uni.makePhoneCall({
      phoneNumber: detail.value.phone
    })
  }
}

// 复制官网链接
const openWebsite = () => {
  if (detail.value?.website) {
    uni.setClipboardData({
      data: detail.value.website,
      success: () => {
        uni.showToast({ title: '链接已复制', icon: 'success' })
      }
    })
  }
}

// 导航前往
const openNavigation = () => {
  if (detail.value?.latitude && detail.value?.longitude) {
    uni.openLocation({
      latitude: detail.value.latitude,
      longitude: detail.value.longitude,
      name: detail.value.name,
      address: detail.value.address
    })
  } else if (detail.value?.address) {
    uni.showToast({ title: '暂无经纬度信息，请使用地图搜索地址', icon: 'none' })
  }
}

// 返回
const goBack = () => {
  uni.navigateBack()
}

// 生命周期
onLoad((options) => {
  if (options.id) {
    institutionId.value = Number(options.id)
    loadDetail(institutionId.value)
  }
})
</script>

